Here is a simple example of a use-after-free bug in C, where a function pointer is overwritten and then called after the memory it points to has been freed:

```c
#include <stdio.h>
#include <stdlib.h>

typedef void (*func_ptr)(void);

void vulnerable_function() {
    printf("vulnerable_function called\n");
}

void attacker_function() {
    printf("attacker_function called\n");
}

int main() {
    func_ptr func_ptr_vuln = &vulnerable_function;
    func_ptr func_ptr_attacker = &attacker_function;

    // Allocate memory for the function pointer
    void *ptr = malloc(sizeof(func_ptr));

    // Copy the address of the vulnerable function to the allocated memory
    memcpy(ptr, &func_ptr_vuln, sizeof(func_ptr));

    // Call the vulnerable function
    (*(func_ptr)ptr)();

    // Free the memory allocated for the function pointer
    free(ptr);

    // Overwrite the function pointer with the address of the attacker function
    memcpy(ptr, &func_ptr_attacker, sizeof(func_ptr));

    // Call the function pointer, which now points to the attacker function
    (*(func_ptr)ptr)();

    return 0;
}
```

In this example, the `vulnerable_function` is called before the memory it is stored in is freed. After the memory is freed, the attacker overwrites the function pointer with the address of the `attacker_function`. When the function pointer is called again, it points to the `attacker_function`, allowing the attacker to execute arbitrary code.

